            ]
        }
    };

    const tabsEl = document.getElementById('iw-tabs');
    const gridEl = document.getElementById('iw-grid');
    let activeCategory = 'MostPopular';

    /* ===== Render Tabs ===== */
    function renderTabs() {
        tabsEl.innerHTML = '';
        for (const [key, cat] of Object.entries(instrumentsData)) {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'iw-tab-btn' + (key === activeCategory ? ' active' : '');
            btn.textContent = cat.categoryName;
            btn.addEventListener('click', () => {
                activeCategory = key;
                renderTabs();
                renderGrid();
            });
            tabsEl.appendChild(btn);
        }
    }

    /* ===== Draw Sparkline ===== */
    function drawSparkline(canvas, data, isUp) {
        const ctx = canvas.getContext('2d');
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
        ctx.scale(dpr, dpr);
        const w = rect.width;
        const h = rect.height;

        if (!data || data.length < 2) return;

        const min = Math.min(...data);
        const max = Math.max(...data);
        const range = max - min || 1;
        const pad = 4;

        // gradient fill
        const grad = ctx.createLinearGradient(0, 0, 0, h);
        if (isUp) {
            grad.addColorStop(0, 'rgba(0,214,143,0.18)');
            grad.addColorStop(1, 'rgba(0,214,143,0.0)');
        } else {
            grad.addColorStop(0, 'rgba(255,77,106,0.18)');
            grad.addColorStop(1, 'rgba(255,77,106,0.0)');
        }

        const stepX = (w - pad * 2) / (data.length - 1);
        const points = data.map((v, i) => ({
            x: pad + i * stepX,
            y: pad + (1 - (v - min) / range) * (h - pad * 2)
        }));

        // fill area
        ctx.beginPath();
        ctx.moveTo(points[0].x, points[0].y);
        for (let i = 1; i < points.length; i++) {
            const xc = (points[i - 1].x + points[i].x) / 2;
            const yc = (points[i - 1].y + points[i].y) / 2;
            ctx.quadraticCurveTo(points[i - 1].x, points[i - 1].y, xc, yc);
        }
        ctx.quadraticCurveTo(points[points.length - 2].x, points[points.length - 2].y, points[points.length - 1].x, points[points.length - 1].y);
        ctx.lineTo(points[points.length - 1].x, h);
        ctx.lineTo(points[0].x, h);
        ctx.closePath();
        ctx.fillStyle = grad;
        ctx.fill();

        // line
        ctx.beginPath();
        ctx.moveTo(points[0].x, points[0].y);
        for (let i = 1; i < points.length; i++) {
            const xc = (points[i - 1].x + points[i].x) / 2;
            const yc = (points[i - 1].y + points[i].y) / 2;
            ctx.quadraticCurveTo(points[i - 1].x, points[i - 1].y, xc, yc);
        }
        ctx.quadraticCurveTo(points[points.length - 2].x, points[points.length - 2].y, points[points.length - 1].x, points[points.length - 1].y);
        ctx.strokeStyle = isUp ? '#00d68f' : '#ff4d6a';
        ctx.lineWidth = 1.8;
        ctx.stroke();

        // end dot
        const last = points[points.length - 1];
        ctx.beginPath();
        ctx.arc(last.x, last.y, 3, 0, Math.PI * 2);
        ctx.fillStyle = isUp ? '#00d68f' : '#ff4d6a';
        ctx.fill();
    }

    /* ===== Format Price ===== */
    function fmtPrice(val, precision) {
        return Number(val).toLocaleString('en-US', { minimumFractionDigits: precision, maximumFractionDigits: precision });
    }

    /* ===== Render Grid ===== */
    function renderGrid() {
        const cat = instrumentsData[activeCategory];
        if (!cat) return;
        gridEl.innerHTML = '';

        cat.instruments.forEach((inst, idx) => {
            const isUp = inst.changeRate >= 0;
            const card = document.createElement('div');
            card.className = 'iw-card';
            card.style.animationDelay = (idx * 0.06) + 's';

            card.innerHTML = `
                <div class="iw-card-top">
                    <img class="iw-card-icon" src="${inst.icon}" alt="${inst.name}" loading="lazy" onerror="this.style.display='none'">
                    <div class="iw-card-info">
                        <div class="iw-card-name">${inst.name}</div>
                        <div class="iw-card-symbol">${inst.symbol}</div>
                    </div>
                    <div class="iw-card-change ${isUp ? 'up' : 'down'}">
                        ${isUp ? '+' : ''}${inst.changeRate.toFixed(2)}%
                    </div>
                </div>
                <div class="iw-card-chart">
                    <canvas id="iw-chart-${activeCategory}-${idx}"></canvas>
                </div>
                <div class="iw-card-prices">
                    <div class="iw-price-box">
                        <div class="iw-price-label">Sell</div>
                        <div class="iw-price-val">${fmtPrice(inst.sellPrice, inst.precision)}</div>
                    </div>
                    <div class="iw-price-box">
                        <div class="iw-price-label">Buy</div>
                        <div class="iw-price-val">${fmtPrice(inst.buyPrice, inst.precision)}</div>
                    </div>
                </div>
                <div class="iw-sentiment">
                    <span class="iw-buy-pct">${inst.buyPct.toFixed(0)}% Buy</span>
                    <div class="iw-sentiment-bar">
                        <div class="iw-sentiment-fill" style="width:${inst.buyPct}%"></div>
                    </div>
                    <span class="iw-sell-pct">${inst.sellPct.toFixed(0)}% Sell</span>
                </div>
                <div class="iw-card-cta">
                    <a href="{{ route('register') }}" class="iw-btn iw-btn-sell">Sell</a>
                    <a href="{{ route('register') }}" class="iw-btn iw-btn-buy">Buy</a>
                </div>
            `;
            gridEl.appendChild(card);

            // Draw sparkline after DOM paint
            requestAnimationFrame(() => {
                const canvas = document.getElementById(`iw-chart-${activeCategory}-${idx}`);
                if (canvas) drawSparkline(canvas, inst.chartData, isUp);
            });
        });
    }

    /* ===== Init ===== */
    renderTabs();
    renderGrid();

    // Redraw sparklines on resize
    let resizeTimer;
    window.addEventListener('resize', () => {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(() => {
            document.querySelectorAll('.iw-card-chart canvas').forEach((canvas, idx) => {
                const cat = instrumentsData[activeCategory];
                if (cat && cat.instruments[idx]) {
                    drawSparkline(canvas, cat.instruments[idx].chartData, cat.instruments[idx].changeRate >= 0);
                }
            });
        }, 200);
    });
})();
</script>

