<script>
    (function() {
        const widgetId = "instrument-widget-b43eb795efa24ca39f4b4ab88244bdd8";
        const styleHref = "tools/css/instruments-widget.css";
        const widgetScriptSrc = "tools/js/instrumentsWidget.min.js";
        const vueScriptSrc = "tools/js/vendors/vue/vue.min.js"; // Get the path from C#

        function loadStyle(href) {
            if (!document.getElementById('instruments-widget-font-style')) {
                const style = document.createElement('style');
                style.id = 'instruments-widget-font-style';
                style.textContent = `
                    @font-face {
                        font-family: "icomoon";
                        src: url("tools/fonts/icons/icomoon.woff2") format("woff2");
                        font-weight: normal;
                        font-style: normal;
                        font-display: block;
                    }
                    [v-cloak] { visibility:hidden; }
                `;
                document.head.appendChild(style);
            }
            if (!document.querySelector(`link[href="${href}"]`)) {
                const link = document.createElement('link');
                link.rel = 'stylesheet';
                link.type = 'text/css';
                link.href = href;
                document.head.appendChild(link);
            }
        }
        
        function runWidgetInit() {
            const widgetElement = document.getElementById(widgetId);
            if (widgetElement && typeof initInstrumentsWidget === 'function') {
                initInstrumentsWidget(widgetElement);
            } else if (!widgetElement) {
                 console.error("Widget installer: Cannot find element " + widgetId);
            } else {
                 console.error("Widget installer: initInstrumentsWidget() function not found.");
            }
        }
        
        function loadWidgetScript() {
            const existingScript = document.querySelector(`script[src="${widgetScriptSrc}"]`);
            if (!existingScript) {
                const script = document.createElement('script');
                script.src = widgetScriptSrc;
                script.onload = runWidgetInit; // When done, run the final init
                document.body.appendChild(script);
            } else {
                if (typeof initInstrumentsWidget === 'function') {
                    runWidgetInit(); // Already loaded, just run
                } else {
                    existingScript.addEventListener('load', runWidgetInit); // Still loading, wait for it
                }
            }
        }

        // This function checks for Vue, loads it if missing, and uses loadWidgetScript as its callback.
        function loadVueAndContinue() {
            // First, check if Vue is already globally available
            if (typeof Vue !== 'undefined') {
                loadWidgetScript(); // Vue exists, just go load the widget script
                return;
            }

            // Vue doesn't exist. We must load it.
            const existingVueScript = document.querySelector(`script[src="${vueScriptSrc}"]`);
            
            if (!existingVueScript) {
                // Create the script tag for Vue
                const vueScript = document.createElement('script');
                vueScript.src = vueScriptSrc;
                
                // When VUE finishes loading, its callback is to load our WIDGET script
                vueScript.onload = loadWidgetScript; 
                
                document.body.appendChild(vueScript);
            } else {
                existingVueScript.addEventListener('load', loadWidgetScript);
            }
        }
        loadStyle(styleHref);
        loadVueAndContinue();
    })();
</script>
